mapper.select:
SELECT
    COUNT(*) AS fileCount,
    COALESCE(SUM(size), 0) AS fileSize
FROM infra_file
WHERE deleted = false

    AND tenant_id = ${@com.lz.framework.tenant.core.context.TenantContextHolder@getTenantId()}


    AND config_id = (SELECT id FROM infra_file_config WHERE config_key = #{configKey} AND deleted = false)


    AND name LIKE CONCAT('%', #{name}, '%')


    AND path LIKE CONCAT('%', #{path}, '%')


    AND path LIKE CONCAT(#{absolutePath}, '%')


    AND path LIKE CONCAT('%', #{relativePath})


    AND type = #{type}



        AND size = #{size[0]}


        AND size BETWEEN #{size[0]} AND #{size[1]}



    AND name LIKE CONCAT('%', #{moduleType}, '%')


    AND create_time BETWEEN #{createTime[0]} AND #{createTime[1]}
